const JSON_PLACEHOLDER_BASE_URL = 'https://jsonplaceholder.typicode.com'

async function fetchJson<T>(
  input: string,
  init?: RequestInit & { next?: NextFetchRequestConfig }
): Promise<T> {
  const response = await fetch(input, init)

  if (!response.ok) {
    throw new Error(`Request failed with status ${response.status}`)
  }

  return (await response.json()) as T
}

export async function getRecentPosts(): Promise<Post[]> {
  return fetchJson<Post[]>(
    `${JSON_PLACEHOLDER_BASE_URL}/posts?_limit=5`,
    { cache: 'no-store' }
  )
}

export async function getAllPosts(): Promise<Post[]> {
  return fetchJson<Post[]>(
    `${JSON_PLACEHOLDER_BASE_URL}/posts`,
    { next: { revalidate: 60 } }
  )
}

export async function getPreviewPostIds(): Promise<string[]> {
  const posts = await fetchJson<Post[]>(
    `${JSON_PLACEHOLDER_BASE_URL}/posts`,
    { next: { revalidate: 300 } }
  )

  return posts.slice(0, 10).map((post) => String(post.id))
}

export async function getPostById(id: string): Promise<Post | null> {
  const response = await fetch(`${JSON_PLACEHOLDER_BASE_URL}/posts/${id}`, {
    next: { revalidate: 300 },
  })

  if (!response.ok) {
    return null
  }

  return (await response.json()) as Post
}

export async function getCommentsByPostId(id: string): Promise<Comment[]> {
  return fetchJson<Comment[]>(
    `${JSON_PLACEHOLDER_BASE_URL}/posts/${id}/comments`,
    { next: { revalidate: 300 } }
  )
}

